    [Fact]
    public void WFiltro_QuemCadHasValidValue_ShouldAddParameterAndWhereClause()
    {
        // Arrange
        var QuemCadValue = 1;
        var filtro = new FilterOutrasPartesCliente
        {
            QuemCad = QuemCadValue,
            LogicalOperator = " AND "
        };
        // Act
        var result = _serviceS.WFiltroOutrasPartesCliente(filtro);
        // Assert
        result.Should().NotBeNull();
        // Check parameter
        var QuemCadParameter = result.Value.parametros.FirstOrDefault(p => p.ParameterName == $"@{DBOutrasPartesClienteDicInfo.QuemCad}");
        QuemCadParameter.Should().NotBeNull();
        QuemCadParameter.Value.Should().Be(QuemCadValue);
        // Check where clause
        result.Value.where.Should().Contain($"[{DBOutrasPartesClienteDicInfo.PTabelaNome}].[{DBOutrasPartesClienteDicInfo.QuemCad}] = @{DBOutrasPartesClienteDicInfo.QuemCad}");
    }

